1	import { createContext, useState, useEffect, useCallback, type ReactNode } from 'react'
2	import type { User, LoginRequest } from '@/types/auth'
3	import { authApi } from '@/api/auth'
4	
5	interface AuthContextType {
6	  user: User | null
7	  isLoading: boolean
8	  login: (credentials: LoginRequest) => Promise<void>
9	  logout: () => Promise<void>
10	}
11	
12	export const AuthContext = createContext<AuthContextType | null>(null)
13	
14	export function AuthProvider({ children }: { children: ReactNode }) {
15	  const [user, setUser] = useState<User | null>(null)
16	  const [isLoading, setIsLoading] = useState(true)
17	
18	  useEffect(() => {
19	    const initAuth = async () => {
20	      const accessToken = localStorage.getItem('access_token')
21	      if (!accessToken) {
22	        setIsLoading(false)
23	        return
24	      }
25	      try {
26	        const { data } = await authApi.me()
27	        setUser(data.user)
28	      } catch {
29	        localStorage.removeItem('access_token')
30	        localStorage.removeItem('refresh_token')
31	      } finally {
32	        setIsLoading(false)
33	      }
34	    }
35	    initAuth()
36	  }, [])
37	
38	  const login = useCallback(async (credentials: LoginRequest) => {
39	    const { data } = await authApi.login(credentials)
40	    localStorage.setItem('access_token', data.access_token)
41	    localStorage.setItem('refresh_token', data.refresh_token)
42	    setUser(data.user)
43	  }, [])
44	
45	  const logout = useCallback(async () => {
46	    const refreshToken = localStorage.getItem('refresh_token')
47	    try {
48	      if (refreshToken) {
49	        await authApi.logout(refreshToken)
50	      }
51	    } catch {
52	      // Ignore logout errors
53	    } finally {
54	      localStorage.removeItem('access_token')
55	      localStorage.removeItem('refresh_token')
56	      setUser(null)
57	    }
58	  }, [])
59	
60	  return (
61	    <AuthContext.Provider value={{ user, isLoading, login, logout }}>
62	      {children}
63	    </AuthContext.Provider>
64	  )
65	}
